                const rowSelectable =
                  selectionEnabled && !!row.athleteEmail && !rowAlreadyInvited
                return (
                  <TableRow key={rowKey}>
                    {selectionEnabled ? (
                      <TableCell>
                        <Checkbox
                          checked={selectedKeys?.has(rowKey) ?? false}
